71	/// A fact / relation atom occupying one premise or conclusion cell, e.g.
72	/// `!SessionKey( <…>, $A, H1 )`. `name` is the fact symbol (may start with `!`
73	/// for a persistent fact); `args` are its term arguments.
74	#[derive(Clone, Debug)]
75	pub struct Fact {
76	    pub name: String,
77	    pub args: Vec<Term>,
78	}
79	
80	impl Fact {
81	    pub fn new(name: &str, args: Vec<Term>) -> Self {
82	        Fact { name: name.to_string(), args }
83	    }
84	
85	    /// Flat (un-wrapped, un-escaped) surface rendering with **fact spacing**:
86	    /// `Name( a, b )`, and `Name( )` when it has no arguments. Argument terms use
87	    /// the ordinary term rendering (functions `f(a, b)` without inner spaces,
88	    /// tuples `<a, b>`). This matches every un-wrapped fact cell in the corpus.
89	    pub fn render_flat(&self) -> String {
90	        let inner: Vec<String> = self.args.iter().map(Term::render_full).collect();
91	        pad(&self.name, &inner)
92	    }
93	
94	    /// Flat rendering with abbreviations applied to registered sub-terms
95	    /// (`table` maps a term's full rendering to its abbreviation name).
96	    pub fn render_flat_abbrev(&self, table: &std::collections::HashMap<String, String>) -> String {
97	        let inner: Vec<String> = self.args.iter().map(|t| t.render_abbrev(table)).collect();
98	        pad(&self.name, &inner)
99	    }
100	}
101	
102	/// Fact spacing `Name( a, b )`, collapsing to `Name( )` for zero arguments
103	/// (observed: `NoA( )`, `!Semistate_1( )` — a single space between the parens).
104	fn pad(name: &str, args: &[String]) -> String {
105	    if args.is_empty() {
106	        format!("{}( )", name)
107	    } else {
108	        format!("{}( {} )", name, args.join(", "))
109	    }
110	}
111	
112	/// The info cell of a rule instance: `#<temporal> : <rule>` plus, when the rule
113	/// has action facts, `[<action>, …]`. Matches the observed info-cell shape
114	/// (`#i : I_Complete[Complete( … ), …]`, or a bare `#vf.5 : Fresh`).
115	pub fn render_info(temporal: &str, rule: &str, actions: &[Fact]) -> String {
116	    if actions.is_empty() {
117	        format!("#{} : {}", temporal, rule)
118	    } else {
119	        let acts: Vec<String> = actions.iter().map(Fact::render_flat).collect();
120	        format!("#{} : {}[{}]", temporal, rule, acts.join(", "))
121	    }
122	}
123	
124	/// Lay `items` out as a **fill** to a target `width`, starting at column
125	/// `open_col` (the alignment column of the group's first element). Returns the
126	/// physical lines *without* the `&nbsp;` indent — [`join_wrapped`] adds it.
127	///
128	/// Greedy fill: keep appending `sep`-joined items to the current line while it
129	/// fits in `width`; otherwise start a new line. This reproduces the observed
130	/// packing (several short arguments share a line, then a break) **given** the
131	/// width; the width itself is the documented gap.
132	pub fn fill(items: &[String], sep: &str, open_col: usize, width: usize) -> Vec<String> {
133	    if items.is_empty() {
134	        return vec![String::new()];
135	    }
136	    let mut lines: Vec<String> = Vec::new();
137	    let mut cur = String::new();
138	    let mut col = open_col;
139	    for (i, it) in items.iter().enumerate() {
140	        let piece = if cur.is_empty() {
141	            it.clone()
142	        } else {
143	            format!("{}{}", sep, it)
144	        };
145	        if !cur.is_empty() && col + piece.chars().count() > width {
146	            lines.push(std::mem::take(&mut cur));
147	            col = open_col;
148	            cur.push_str(it);
149	            col += it.chars().count();
150	        } else {
151	            cur.push_str(&piece);
152	            col += piece.chars().count();
153	        }
154	        let _ = i;
155	    }
156	    lines.push(cur);
157	    lines
158	}
