1	//! Graph simplification / abbreviation options (BEHAVIOR.md §5, §7).
2	//!
3	//! The web UI exposes four "Graph simplification" levels (`lvl0`..`lvl3`
4	//! toggles: *off*, *L1*, *L2*, *L3*) plus an abbreviation toggle. These are not
5	//! separate endpoints — the client JS stores them in cookies and appends them as
6	//! **query parameters** to the graph URL. The observed parameter set (mined from
7	//! the UI JS and confirmed by live probes; see QUERIES.log) is:
8	//!
9	//! | param            | when the UI sends it            | server-side effect (observed)             |
10	//! |------------------|---------------------------------|-------------------------------------------|
11	//! | `simplification=N` | always (N = level, default 2) | selects the level; N alone changed **no** probed graph (L1≡L2≡L3 byte-identical) |
12	//! | `uncompact`      | only at level 0                 | disables node COMPACTION                  |
13	//! | `uncompress`     | only at level 0                 | disables system COMPRESSION               |
14	//! | `unabbreviate`   | when the abbreviate cookie is off | disables the abbreviation pass          |
15	//! | `no-auto-sources`| when auto-sources cookie is off | disables auto-source-lemma precomputation |
16	//! | `clustering=true`| when clustering cookie is on    | forces role clustering                    |
17	//!
18	//! Observed transforms (live diffs, NAXOS/NSLPK3 case graphs):
19	//!   * **compression** (on unless `uncompress`): Fresh rules (`Fr( ~x )` sources)
20	//!     and single intruder-derivation rules are hidden / collapsed — `!KU` facts
21	//!     become gray ellipses and Fresh sources disappear; turning it OFF re-expands
22	//!     them into full `record` rule nodes (node/edge counts grow markedly).
23	//!   * **compaction** (on unless `uncompact`): a lone intruder `isend`/`coerce`
24	//!     rule is drawn as a single ellipse (e.g. `#vf.7 : isend`); OFF draws it as a
25	//!     full `{!KU(m)}|{#vf : isend[K(m)]}|{In(m)}` record.
26	//!   * **abbreviation** (on unless `unabbreviate`): complex sub-terms are replaced
27	//!     by legend names and a `{ rank="sink"; … }` legend block is emitted; OFF
28	//!     inlines every term in full and omits the legend block entirely.
29	//!
30	//! The default (no query params, as the corpus was crawled) equals level ≥1:
31	//! compressed + compacted + abbreviated. The distinction between L1/L2/L3 was not
32	//! reproduced on any probed graph and is a documented GAP — as is the *content* of
33	//! compression/compaction, which needs the GPL solver (this crate models the
34	//! flags and the abbreviation on/off transform, taking the node set as input).
35	
36	/// The observed graph-rendering options. `abbreviate` is the one transform this
37	/// crate applies directly (drop the legend + inline terms when false); the
38	/// compress/compact flags are recorded and documented — their *content* is a
39	/// solver-side GAP, so a caller supplies the already-(un)compressed node set.
40	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
41	pub struct Options {
42	    /// Graph simplification level 0..=3 (UI default 2).
43	    pub level: u8,
44	    /// Run the abbreviation pass (emit a legend). `false` ⇒ `unabbreviate`.
45	    pub abbreviate: bool,
46	    /// Apply node compaction. `false` ⇒ `uncompact` (sent by the UI at level 0).
47	    pub compact: bool,
48	    /// Apply system compression. `false` ⇒ `uncompress` (sent by the UI at level 0).
49	    pub compress: bool,
50	    /// Force role clustering (`clustering=true`).
51	    pub clustering: bool,
52	}
53	
54	impl Default for Options {
55	    /// The corpus/default rendering: level 2, abbreviated, compacted, compressed.
56	    fn default() -> Self {
57	        Options { level: 2, abbreviate: true, compact: true, compress: true, clustering: false }
58	    }
59	}
60	
61	impl Options {
62	    /// The UI's level-0 preset: compaction and compression OFF (the UI sends
63	    /// `uncompact` + `uncompress` + `simplification=0`).
64	    pub fn level0() -> Self {
65	        Options { level: 0, compact: false, compress: false, ..Options::default() }
66	    }
67	
68	    /// Reconstruct the query string the UI appends for these options, in the
69	    /// UI's parameter order (`uncompact`, `uncompress` first — only at level 0 —
70	    /// then `unabbreviate`, then `simplification`, then `clustering`). Returns the
71	    /// part after `?` (empty if nothing would be appended). Byte-shaped to match
72	    /// the observed `?uncompact=&uncompress=&simplification=0` form.
73	    pub fn query_string(&self) -> String {
74	        let mut parts: Vec<String> = Vec::new();
75	        if self.level == 0 {
76	            parts.push("uncompact=".into());
77	            parts.push("uncompress=".into());
78	        }
79	        if !self.abbreviate {
80	            parts.push("unabbreviate=".into());
81	        }
82	        parts.push(format!("simplification={}", self.level));
83	        if self.clustering {
84	            parts.push("clustering=true".into());
85	        }
86	        parts.join("&")
87	    }
88	}
